import { Controller, Get, Post, UseGuards, Req, Res } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { AuthGuard } from '@nestjs/passport';
import { GoogleOAuthGuard } from './guards/google.guard';
import { AuthService } from './auth.service';
import type { Response } from 'express';
import { Public } from './decorators/public.decorator';
import type { RequestWithUser } from './interfaces/request-with-user.interface';

@Controller('auth')
export class AuthController {
  constructor(
    private readonly configService: ConfigService,
    private readonly authService: AuthService,
  ) {}

  @Public()
  @Get('google')
  @UseGuards(GoogleOAuthGuard)
  async googleAuth() {}

  @Public()
  @Get('google/callback')
  @UseGuards(GoogleOAuthGuard)
  async googleAuthCallback(@Req() req: RequestWithUser, @Res() res: Response) {
    const { accessToken, refreshToken } = await this.authService.generateTokens(
      req.user.id,
    );

    res.cookie(
      'Authentication',
      accessToken,
      this.authService.accessCookieOptions,
    );
    res.cookie('Refresh', refreshToken, this.authService.refreshCookieOptions);

    const clientUrl = this.configService.getOrThrow<string>('clientUrl');
    res.redirect(clientUrl);
  }

  @Public()
  @Post('refresh')
  @UseGuards(AuthGuard('jwt-refresh'))
  async refresh(
    @Req() req: RequestWithUser,
    @Res({ passthrough: true }) res: Response,
  ) {
    const { accessToken, refreshToken } = await this.authService.generateTokens(
      req.user.id,
    );

    res.cookie(
      'Authentication',
      accessToken,
      this.authService.accessCookieOptions,
    );
    res.cookie('Refresh', refreshToken, this.authService.refreshCookieOptions);

    return { success: true };
  }

  @Post('logout')
  async logout(@Res({ passthrough: true }) res: Response) {
    res.clearCookie('Authentication', this.authService.accessCookieOptions);
    res.clearCookie('Refresh', this.authService.refreshCookieOptions);
    return { success: true };
  }
}

import {
  ExecutionContext,
  Injectable,
  UnauthorizedException,
  Logger,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { AuthGuard } from '@nestjs/passport';
import { IS_PUBLIC_KEY } from '../decorators/public.decorator';

@Injectable()
export class JwtAuthGuard extends AuthGuard('jwt') {
  private readonly logger = new Logger(JwtAuthGuard.name);

  constructor(private reflector: Reflector) {
    super();
  }

  canActivate(context: ExecutionContext) {
    const isPublic = this.reflector.getAllAndOverride<boolean>(IS_PUBLIC_KEY, [
      context.getHandler(),
      context.getClass(),
    ]);
    if (isPublic) {
      return true;
    }
    return super.canActivate(context);
  }

  handleRequest(err, user, info) {
    if (err || !user) {
      if (info) {
        this.logger.warn(`Authentication failed: ${info.message || info}`);
      }
      if (err) {
        this.logger.error(`Authentication error: ${err.message || err}`);
      }
      throw err || new UnauthorizedException(info?.message || 'Unauthorized');
    }
    return user;
  }
}

import { PassportStrategy } from '@nestjs/passport';
import { Strategy } from 'passport-google-oauth20';
import { Injectable, UnauthorizedException } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { AdminUserService } from 'src/portfolio/services/admin-user.service';
import { AdminUserProviderService } from 'src/portfolio/services/admin-user-provider.service';

@Injectable()
export class GoogleStrategy extends PassportStrategy(Strategy, 'google') {
  constructor(
    configService: ConfigService,
    private adminUserService: AdminUserService,
    private adminUserProviderService: AdminUserProviderService,
  ) {
    super({
      clientID: configService.getOrThrow<string>('google.clientId'),
      clientSecret: configService.getOrThrow<string>('google.clientSecret'),
      callbackURL: configService.getOrThrow<string>('google.callbackUrl'),
      scope: ['email', 'profile'],
    });
  }

  async validate(accessToken: string, refreshToken: string, profile: any) {
    const { id, emails } = profile;
    const email = emails[0]?.value;

    if (!email) {
      throw new UnauthorizedException('Unauthorized. No email.');
    }

    const userProviderLink =
      await this.adminUserProviderService.findByProviderId('google', id);
    if (userProviderLink) {
      if (!userProviderLink.adminUser.isActive) {
        throw new UnauthorizedException('Account is deactivated.');
      }
      return userProviderLink.adminUser;
    }

    const user = await this.adminUserService.findByEmail(email);
    if (!user) {
      throw new UnauthorizedException('Unauthorized. Email not in whitelist.');
    }

    if (!user.isActive) {
      throw new UnauthorizedException('Account is deactivated.');
    }

    await this.adminUserProviderService.addOrUpdate({
      provider: 'google',
      providerId: id,
      adminUser: user,
    });

    return user;
  }
}

import { ExtractJwt, Strategy } from 'passport-jwt';
import { PassportStrategy } from '@nestjs/passport';
import { Injectable, UnauthorizedException } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { Request } from 'express';
import { AdminUserService } from 'src/portfolio/services/admin-user.service';
import { JwtPayload } from '../interfaces/jwt-payload.interface';

@Injectable()
export class JwtRefreshStrategy extends PassportStrategy(
  Strategy,
  'jwt-refresh',
) {
  constructor(
    configService: ConfigService,
    private adminUserService: AdminUserService,
  ) {
    super({
      jwtFromRequest: ExtractJwt.fromExtractors([
        (request: Request) => {
          return request?.cookies?.Refresh;
        },
      ]),
      ignoreExpiration: false,
      secretOrKey: configService.getOrThrow<string>('jwt.refreshSecret'),
      issuer: 'portfolio-backend',
      audience: 'portfolio-admin',
    });
  }

  async validate(payload: JwtPayload) {
    const user = await this.adminUserService.findById(payload.sub);
    if (!user || !user.isActive) {
      throw new UnauthorizedException();
    }
    return user;
  }
}

